import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),o={name:"審計報告庫/財務審計/4967_十銓/20260428/F16_大股東成本與籌碼結構審計_投資研究員.md"};function r(n,a,s,c,h,_){return e(),i("div",null,[...a[0]||(a[0]=[l('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務見解。</p><h1 id="f16-大股東成本與籌碼結構審計-投資研究員-審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員-審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：全體董監持股4.7%+零質押，無5%以上股東，股權高度分散。董監由3.6%升至4.7%正向但利益綁定不足，下檔無機構支撐。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2026年3月最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：董監持股4.7%（2026/3，年初3.6%，+1.1pp）；質押0%；無5%以上股東；千張大戶12人/23.27%（4/24）；400張以上34.61%。</li><li><strong>診斷見解</strong>：4.7%遠低於S級門檻25%，利益綁定度不足。零質押排除斷頭風險，但持股過低使管理層損益一致性偏弱。千張大戶23.27%尚可，但減碼趨勢需關注。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="董監持股結構與信心判定" tabindex="-1">董監持股結構與信心判定 <a class="header-anchor" href="#董監持股結構與信心判定" aria-label="Permalink to &quot;董監持股結構與信心判定&quot;">​</a></h3><ul><li><strong>核心重點</strong>：四名董事合計3,995仟股（4.7%），夏紹安2.11%最高，夏澹寧1.67%，家族合計3.78%。2025年由3.6%升至4.7%，主因10-12月CB轉換稀釋後內部人小額增持。第三次CB 1,200,000仟元已全數轉換為14,814仟股，稀釋效應顯著。</li><li><strong>深度見解</strong>：管理層未在CB轉換後積極增持以維持持股水位，反映對股價的「被動態度」。零質押在此結構下實為「自然結果」—即使股價腰斬，董監個人損失有限，無需質押融資。低持股代表經營決策時小股東缺乏管理層的「痛感共鳴」，潛在代理成本偏高。</li></ul><h3 id="大股東成本與持股趨勢" tabindex="-1">大股東成本與持股趨勢 <a class="header-anchor" href="#大股東成本與持股趨勢" aria-label="Permalink to &quot;大股東成本與持股趨勢&quot;">​</a></h3><ul><li><strong>核心重點</strong>：無5%以上大股東，無法精確估算單一成本區間。千張大戶從1月24.89%降至4月23.27%（人數維持12人），一季減碼1.62pp（約138萬股）。400張以上34.61%。</li><li><strong>深度見解</strong>：大戶「減碼但未離場」，屬典型反彈中部分獲利了結。股價由3月低點188.5元反彈至258.5元（+37%），大戶同步調節。若千張大戶跌破20%或人數降至10人以下，將確認籌碼結構性轉弱。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一（低持股代理問題）</strong>：董監持股4.7%在記憶體族群屬最低，對照創見12%、群聯15%，利益綑綁度嚴重不足。2025年CB轉換後管理層未增持護盤，已暗示對股價的被動態度。經營關鍵時刻（庫存去化、客戶逾期），低持股管理層傾向保守，小股東承受全部下檔風險而管理層損失有限。</li><li><strong>空頭風險二（大戶減碼+籌碼分散）</strong>：千張大戶由24.89%續降至23.27%，疊加投信持續賣超（見F17），籌碼從集中轉向分散。股價反彈37%後大戶減碼，透露其認為當前估值已充分反映利多。零質押在此背景非利多——管理層無足夠股份可供質押，成長完全依賴盈餘與CB，記憶體景氣反轉時缺乏槓桿護盤空間。需追蹤5月千張大戶變化，跌破20%將確認轉弱。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK（股權分散表、法人持股數據）</li><li><strong>yfinance</strong>: 不適用</li><li><strong>年報/法說</strong>: OK — 2025合併財報附註十四(四)：「無持有股數達百分之五以上之股東」</li><li><strong>關鍵核對碼</strong>： <ul><li>董監持股: 4.7%（goodinfo.tw, 2026/3）</li><li>質押比例: 0%（statementdog.com, 2026/3）</li><li>千張大戶: 12人/23.27%（wantgoo.com, 2026/4/24）</li><li>400張以上: 34.61%（wantgoo.com, 2026/4/24）</li></ul></li></ul>',17)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
